/** @type layout[] */
var layouts = [];
if (MY_PAGE === 1) layouts = storage0.getMyVar('items');
const { image, lazyRule } = $.require('hiker://page/tools');
let html;
let type = getMyVar('type');

if (MY_PAGE === 1) {
  let url = 'https://cn1.91short.com' + (type === 'short' ? getMyVar('short') : getMyVar('film'));
  if (type === 'actor') url = 'https://cn1.91short.com/film/home_actor_list';
  html = request(url);
  putMyVar('url', html.match('let url="(.*?)"')[1]);
} else {
  if (getMyVar('url') !== 'fail') {
    html = request('https://cn1.91short.com' + getMyVar('url'));
    putMyVar('url', pdfh(html, 'script&&Html'));
  }
}
let list = pdfa(html, 'body&&.module');
if (list.length > 0) {
  for (let module of list) {
    let title = pdfh(module, '.module-title&&Text');
    let temp = {
      url: 'hiker://empty',
      title,
      col_type: 'avatar',
      img: 'https://img95.699pic.com/element/40142/5043.png_860.png',
    };
    if (pdfa(module, '.module-title&&a').length > 0) {
      temp.url = `hiker://empty##${pdfh(module, '.module-title&&a&&href')}##fypage`;
      temp.img = image(pdfh(module, '.module-title&&img&&data-cover'));
    }
    if (title) layouts.push(temp);
    let module_item = pdfa(module, '.module-list&&.module-item');
    if (type === 'actor') module_item.pop();
    for (let item of module_item) {
      layouts.push({
        title: pdfh(item, 'img&&alt'),
        desc: pdfh(item, 'span&&Text'),
        pic_url: image(pdfh(item, 'img&&data-cover')),
        url: lazyRule(`https://cn1.91short.com${pdfh(item, 'a&&href')}`),
      });
    }
    let actor_part = pdfa(module, '.module-list&&.actor_part');
    if (actor_part.length > 0)
      for (let actor of actor_part) {
        layouts.push({
          url: `hiker://empty##${pdfh(actor, 'a&&href')}##fypage`,
          title: pdfh(actor, 'a&&title'),
          col_type: 'icon_2_round',
          img: image(pdfh(actor, 'img&&data-cover')),
        });
      }
  }
} else {
  let module_item = pdfa(html, 'body&&.module-item');
  if (module_item.length > 0)
    for (let item of module_item) {
      layouts.push({
        title: pdfh(item, 'img&&alt'),
        desc: pdfh(item, 'span&&Text'),
        pic_url: image(pdfh(item, 'img&&data-cover')),
        url: lazyRule(`https://cn1.91short.com${pdfh(item, 'a&&href')}`),
      });
    }
  let actor_part = pdfa(html, 'body&&.actor_part');
  if (actor_part.length > 0)
    for (let actor of actor_part) {
      layouts.push({
        url: `hiker://empty##${pdfh(actor, 'a&&href')}##fypage`,
        title: pdfh(actor, 'a&&title'),
        col_type: 'icon_2_round',
        img: image(pdfh(actor, 'img&&data-cover')),
      });
    }
}
setResult(layouts);

