    this.color = '#12b668'
    this.boundary = 'blank_block'
}
hiker_ClassHeader.prototype = {
    constructor: hiker_ClassHeader,
    load(el) {
        this.arr.forEach((v) => {
            let {
                id,
                class_name,
                class_url
            } = v,
            selected = JSON.stringify(this.getClass(id))
            class_name.forEach((name, i) => {
                let url = class_url[i],
                    now = JSON.stringify({
                        name: name,
                        url: url
                    })
                el.push({
                    title: selected == now ? '““””' + name.fontcolor(this.color).bold() : name,
                    url: selected == now ? 'hiker://empty' : $('#noLoading#').lazyRule((id, now) => {
                        putMyVar('$hikerClassHeader_' + id, now)
