if (!r || r.length <= 5) {
    let ru = $.toString(() => {
        return "海阔视界规则分享，当前分享的是：小程序￥home_rule_v2￥base64://@云盘汇影@"
    });
    confirm({
        title: MY_RULE.title + '提示',
        content: '本规则依赖云盘汇影规则，点击下面的确定按钮导入',
        confirm: ru,
        cancel: ru
    })
}
let u = MY_URL.split("##")[1];

function loadUrl(u) {
    let desc = "auto";
    for (let it of white) {
        if (u.includes(it)) {
            desc = "100%&&float";
        }
    }
    if (getAppVersion() >= 3018) {
        desc = "float&&top";
    }
    setResult([{
        col_type: "x5_webview_single",
        url: u,
        desc: desc,
        extra: {
            canBack: true,
            urlInterceptor: $.toString(() => {
                if (input.startsWith('https://www.aliyundrive.com/s/')) {
                    return $.toString((url) => {
                        fba.open(JSON.stringify({
                            rule: '云盘汇影',
                            url: 'hiker://page/detail?rule=云盘汇影&url=' + url + '??fypage'
                        }));
                    }, input)
                }
            }),
            disableX5: true
        }
    }])
}
if (u == "all") {
    let cls = getMyVar("cls", "");
    if (cls) {
        u = cls;
        loadUrl(u);
        clearMyVar("cls");
    } else {
        let r = JSON.parse(fetch("hiker://home@" + MY_RULE.title));
        let cn = r.class_name.split("&");
        let cu = r.class_url.split("&");
        let arr = [];
        if (pic) {
            arr.push({
                title: "",
                url: pic,
                col_type: "card_pic_1",
                desc: "0",
                pic_url: random ? (pic + "#_t=" + Math.ceil(new Date().getTime() / 300000)) : pic
            });
            arr.push({
                col_type: "big_blank_block"
            });


        }
        for (let i = 1; i < cn.length; i++) {
            arr.push({
                title: cn[i],
                url: $().lazyRule((u) => {
                    putMyVar("cls", u);
                    //refreshX5Desc("top&&float");
                    refreshPage();
                    return "hiker://empty";
                }, cu[i]),
                col_type: "text_2",
                desc: "",
                pic_url: ""
            });
        }
        refreshX5Desc("0&&float");
        setResult(arr);
    }
} else {
    loadUrl(u);
}

